#include <stdio.h>
#include <stdlib.h>

static long long count_up_to(long long x) {
    if (x <= 0) return 0;
    long long cycles = x / 10;
    int rem = x % 10;
    long long extra = 0;
    if (rem >= 2) extra++;
    if (rem >= 3) extra++;
    if (rem >= 9) extra++;
    return cycles * 3 + extra;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long ans = count_up_to(R) - count_up_to(L - 1);
        printf("%lld\n", ans);
    }
    return 0;
}

