code.Python3:
import sys

def count_up_to(x: int) -> int:
    if x <= 0:
        return 0
    cycles = x // 10
    rem = x % 10
    extra = 0
    if rem >= 2:
        extra += 1
    if rem >= 3:
        extra += 1
    if rem >= 9:
        extra += 1
    return cycles * 3 + extra

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        L = int(next(it))
        R = int(next(it))
        ans = count_up_to(R) - count_up_to(L - 1)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

